// src/pages/Login.jsx

import { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Login() {

  const nav = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("customer");

  const loginUser = async (e) => {

    e.preventDefault();

    try {

      const res = await axios.post(
        "http://localhost:5000/api/auth/login",
        {
          email,
          password,
          role
        }
      );

      localStorage.setItem(
        "user",
        JSON.stringify(res.data.user)
      );

      if (role === "customer") {

        nav("/customer-dashboard");

      } else {

        nav("/labour-dashboard");

      }

    } catch (err) {

      alert("Invalid Credentials");

    }
  };

  return (

    <div style={styles.page}>

      {/* LEFT DESIGN */}

      <div style={styles.left}>

        <div style={styles.circle1}></div>
        <div style={styles.circle2}></div>

        <div style={styles.brandBox}>

          <div style={styles.logo}>
            D
          </div>

          <h1 style={styles.brand}>
            DailyMajdoor
          </h1>

          <p style={styles.text}>
            Smart Worker Hiring Platform
          </p>

        </div>

      </div>

      {/* LOGIN CARD */}

      <div style={styles.right}>

        <div style={styles.card}>

          <h2 style={styles.title}>
            Sign In
          </h2>

          <p style={styles.subtitle}>
            Continue your journey
          </p>

          <form onSubmit={loginUser}>

            <select
              style={styles.input}
              value={role}
              onChange={(e) =>
                setRole(e.target.value)
              }
            >

              <option value="customer">
                Customer
              </option>

              <option value="labour">
                Labour
              </option>

            </select>

            <input
              type="email"
              placeholder="Email"
              style={styles.input}
              value={email}
              onChange={(e) =>
                setEmail(e.target.value)
              }
            />

            <input
              type="password"
              placeholder="Password"
              style={styles.input}
              value={password}
              onChange={(e) =>
                setPassword(e.target.value)
              }
            />

            <button style={styles.button}>
              Login
            </button>

          </form>

          <p style={styles.bottom}>

            Don't have an account?

            <span
              style={styles.link}
              onClick={() =>
                nav("/register")
              }
            >
              Register
            </span>

          </p>

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    display: "flex",
    fontFamily: "Arial"
  },

  /* LEFT */

  left: {
    width: "40%",
    background:
      "linear-gradient(180deg,#f97316,#ea580c)",
    position: "relative",
    overflow: "hidden",
    display: "flex",
    justifyContent: "center",
    alignItems: "center"
  },

  circle1: {
    position: "absolute",
    width: "280px",
    height: "280px",
    borderRadius: "50%",
    background: "rgba(255,255,255,0.12)",
    top: "-80px",
    left: "-80px"
  },

  circle2: {
    position: "absolute",
    width: "220px",
    height: "220px",
    borderRadius: "50%",
    background: "rgba(255,255,255,0.12)",
    bottom: "-60px",
    right: "-60px"
  },

  brandBox: {
    position: "relative",
    zIndex: 2,
    color: "white",
    textAlign: "center"
  },

  logo: {
    width: "70px",
    height: "70px",
    borderRadius: "20px",
    background: "white",
    color: "#f97316",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    margin: "0 auto 24px auto",
    fontSize: "30px",
    fontWeight: "bold"
  },

  brand: {
    margin: 0,
    fontSize: "42px"
  },

  text: {
    marginTop: "12px",
    fontSize: "16px",
    opacity: 0.9
  },

  /* RIGHT */

  right: {
    width: "60%",
    background: "#f8fafc",
    display: "flex",
    justifyContent: "center",
    alignItems: "center"
  },

  card: {
    width: "360px",
    background: "white",
    padding: "40px",
    borderRadius: "24px",
    boxShadow:
      "0 10px 35px rgba(0,0,0,0.08)"
  },

  title: {
    margin: 0,
    fontSize: "32px",
    color: "#111827"
  },

  subtitle: {
    color: "#6b7280",
    marginTop: "8px",
    marginBottom: "30px",
    fontSize: "14px"
  },

  input: {
    width: "100%",
    padding: "15px",
    marginBottom: "18px",
    borderRadius: "12px",
    border: "1px solid #e5e7eb",
    background: "#f9fafb",
    boxSizing: "border-box",
    fontSize: "14px",
    outline: "none"
  },

  button: {
    width: "100%",
    padding: "15px",
    border: "none",
    borderRadius: "12px",
    background:
      "linear-gradient(135deg,#f97316,#ea580c)",
    color: "white",
    fontWeight: "bold",
    fontSize: "15px",
    cursor: "pointer",
    marginTop: "5px"
  },

  bottom: {
    textAlign: "center",
    marginTop: "24px",
    color: "#6b7280",
    fontSize: "14px"
  },

  link: {
    color: "#f97316",
    marginLeft: "5px",
    cursor: "pointer",
    fontWeight: "bold"
  }

};
